"""
scanner.py
Responsabilidad: Analizar el dispositivo y calcular cuánto caché
existe en cada categoría antes de limpiar.
"""

import os
import glob
from pathlib import Path
from datetime import datetime


def resolver_ruta(ruta: str) -> str:
    """Convierte variables de entorno en rutas reales. Ej: %TEMP% → C:\\Users\\..."""
    return os.path.expandvars(ruta)


def calcular_tamano_carpeta(ruta: str) -> tuple[int, int]:
    """
    Calcula el tamaño total y número de archivos de una carpeta.
    Retorna: (bytes_totales, cantidad_archivos)
    """
    total_bytes = 0
    total_archivos = 0

    try:
        for archivo in Path(ruta).rglob("*"):
            if archivo.is_file():
                try:
                    total_bytes += archivo.stat().st_size
                    total_archivos += 1
                except (PermissionError, OSError):
                    continue
    except (PermissionError, OSError, FileNotFoundError):
        pass

    return total_bytes, total_archivos


def escanear_categoria(key: str, config: dict) -> dict:
    """
    Escanea una categoría individual y retorna sus estadísticas.
    """
    total_bytes = 0
    total_archivos = 0
    disponible = False

    rutas = config.get("paths", [])

    for ruta_raw in rutas:
        ruta_resuelta = resolver_ruta(ruta_raw)
        rutas_expandidas = glob.glob(ruta_resuelta)

        if not rutas_expandidas:
            rutas_expandidas = [ruta_resuelta]

        for ruta in rutas_expandidas:
            if os.path.exists(ruta):
                disponible = True
                bytes_carpeta, archivos_carpeta = calcular_tamano_carpeta(ruta)
                total_bytes += bytes_carpeta
                total_archivos += archivos_carpeta

    return {
        "key": key,
        "label": config.get("label", key),
        "bytes": total_bytes,
        "files": total_archivos,
        "available": disponible,
        "enabled": config.get("enabled", True),
        "requires_admin": config.get("requires_admin", False),
    }


def escanear_dispositivo(categorias: dict) -> dict:
    """
    Escanea todas las categorías activas y retorna un resumen completo.
    Punto de entrada principal del scanner.
    """
    resultados_categorias = []
    total_bytes = 0
    total_archivos = 0

    for key, config in categorias.items():
        if not config.get("paths"):
            continue

        resultado = escanear_categoria(key, config)
        resultados_categorias.append(resultado)

        if resultado["enabled"] and resultado["available"]:
            total_bytes += resultado["bytes"]
            total_archivos += resultado["files"]

    return {
        "scanned_at": datetime.now().isoformat(),
        "total_bytes": total_bytes,
        "total_files": total_archivos,
        "categories": resultados_categorias,
    }


def formatear_tamano(bytes: int) -> str:
    """Convierte bytes a formato legible. Ej: 524288000 → '500.0 MB'"""
    if bytes < 1024:
        return f"{bytes} B"
    elif bytes < 1024 ** 2:
        return f"{bytes / 1024:.1f} KB"
    elif bytes < 1024 ** 3:
        return f"{bytes / 1024 ** 2:.1f} MB"
    else:
        return f"{bytes / 1024 ** 3:.2f} GB"